// // This module extends a 16-bit input to a 32-bit output based on the ExtType signal. If ExtType is 1 and the most significant bit of imm16 is 0, it performs sign-extension by prepending 16 ones to the imm16 value. Otherwise, it prepends 16 zeros.
module top_module(
    input  [15:0] imm16,
    input         ExtType,
    output [31:0] imm32
);assign imm32 = {(imm16[15] == 1'b1 && ExtType == 1'b1) ? 16'hFFFF : 16'h0000, imm16};
endmodule
